mapper.select:
SELECT a.*, c.CPNY_LOCATION AS COMPANY_NAME, TO_CHAR(a.DDATE, 'YYYY-MM-DD') AS DDATE_FORMATTED, GET_GLOBAL_NAME(a.SHIFT_NO, #{lang}) AS SHIFT_NAME, GET_GLOBAL_NAME(a.TYPEID, #{lang}) AS TYPEID_NAME, GET_GLOBAL_NAME(a.OVERTYPEID, #{lang}) AS OVERTYPEID_NAME, GET_GLOBAL_NAME(a.TYPEID_DEFAULT, #{lang}) AS TYPEID_DEFAULT_NAME FROM AR_CALENDER a LEFT JOIN HR_COMPANY c ON a.CPNY_ID = c.CPNY_ID WHERE (a.TYPEID = '1442' OR a.STATUTORY_FLAG = 1)
AND a.CPNY_ID = #{cpnyId}
AND a.IYEAR = #{iyear}
AND a.IMONTH = #{imonth}
AND (a.DDATE_STR LIKE '%' || #{keyword} || '%' OR a.REMARK LIKE '%' || #{keyword} || '%')
ORDER BY a.IYEAR DESC, a.IMONTH, a.IDAY

SELECT a.*, c.CPNY_LOCATION AS COMPANY_NAME, TO_CHAR(a.DDATE, 'YYYY-MM-DD') AS DDATE_FORMATTED, GET_GLOBAL_NAME(a.SHIFT_NO, #{lang}) AS SHIFT_NAME, GET_GLOBAL_NAME(a.TYPEID, #{lang}) AS TYPEID_NAME, GET_GLOBAL_NAME(a.OVERTYPEID, #{lang}) AS OVERTYPEID_NAME, GET_GLOBAL_NAME(a.TYPEID_DEFAULT, #{lang}) AS TYPEID_DEFAULT_NAME FROM AR_CALENDER a LEFT JOIN HR_COMPANY c ON a.CPNY_ID = c.CPNY_ID WHERE a.IYEAR = #{iyear} AND a.IMONTH = #{imonth}
AND a.CPNY_ID = #{cpnyId}
ORDER BY a.IDAY

mapper.update:
UPDATE AR_CALENDER
WORKDAYFLAG = #{workdayflag}, SHIFT_NO = #{shiftNo}, TYPEID = #{typeid}, OVERTYPEID = #{overtypeid}, TYPEID_DEFAULT = #{typeidDefault}, OPERATION_ID = #{operationId}, ACTIVITY = #{activity}, ORDERNO = #{orderno}, STATUTORY_FLAG = #{statutoryFlag}, REMARK = #{remark}, UPDATE_DATE = SYSDATE, UPDATED_BY = #{adminID}
WHERE CPNY_ID = #{cpnyId} AND DDATE_STR = #{ddateStr}

UPDATE AR_CALENDER_GROUP
WORKDAYFLAG = #{workdayflag}, TYPEID = #{typeid}, OVERTYPEID = #{overtypeid}, TYPEID_DEFAULT = #{typeidDefault}, SHIFT_NO = #{shiftNo}, ACTIVITY = #{activity}, UPDATED_BY = #{adminID}, UPDATE_DATE = SYSDATE
WHERE AR_DATE_STR = #{arDateStr} AND CPNY_ID = #{cpnyId} AND GROUP_ID = #{groupId}

mapper.select:
SELECT a.*, c.CPNY_LOCATION AS COMPANY_NAME, TO_CHAR(a.DDATE, 'YYYY-MM-DD') AS DDATE_FORMATTED, GET_GLOBAL_NAME(a.SHIFT_NO, #{lang}) AS SHIFT_NAME, GET_GLOBAL_NAME(a.TYPEID, #{lang}) AS TYPEID_NAME, GET_GLOBAL_NAME(a.OVERTYPEID, #{lang}) AS OVERTYPEID_NAME, GET_GLOBAL_NAME(a.TYPEID_DEFAULT, #{lang}) AS TYPEID_DEFAULT_NAME, GET_GLOBAL_NAME(a.GROUP_ID, #{lang}) AS GROUP_NAME FROM AR_CALENDER_GROUP a LEFT JOIN HR_COMPANY c ON a.CPNY_ID = c.CPNY_ID WHERE a.IYEAR = #{iyear} AND a.IMONTH = #{imonth}
AND a.CPNY_ID = #{cpnyId}
AND a.GROUP_ID = #{groupId}
ORDER BY a.IDAY, a.GROUP_ID

